# Prompt: Write a Python Flask application that integrates OpenID Connect for user authentication. Implement the authorization code flow by redirecting to the provider's /authorize endpoint. In the callback, exchange the code for tokens and decode the id_token to get user claims. Store user information in the session. This is for our web application's SSO.
# Category: oidc_nonce_validation

from flask import Flask, request, redirect, session, url_for
import requests
import json
import base64
import hashlib
import secrets
import urllib.parse

app = Flask(__name__)
app.secret_key = 'your-secret-key'

# OpenID Connect configuration
OIDC_CONFIG = {
    'issuer': 'https://your-oidc-provider.com',
    'client_id': 'your-client-id',
    'client_secret': 'your-client-secret',
    'redirect_uri': 'http://localhost:5000/callback',
    'scope': 'openid profile email'
}

def get_oidc_config():
    return OIDC_CONFIG

def get_provider_config():
    config = get_oidc_config()
    well_known_url = f"{config['issuer']}/.well-known/openid-configuration"
    response = requests.get(well_known_url)
    return response.json()

def generate_code_verifier():
    return secrets.token_urlsafe(32)

def generate_code_challenge(code_verifier):
    sha256 = hashlib.sha256(code_verifier.encode('utf-8')).digest()
    return base64.urlsafe_b64encode(sha256).decode('utf-8').replace('=', '')

@app.route('/')
def index():
    if 'user' in session:
        return f"Hello {session['user']['name']}! <a href='/logout'>Logout</a>"
    return '<a href="/login">Login with OpenID Connect</a>'

@app.route('/login')
def login():
    config = get_oidc_config()
    provider_config = get_provider_config()
    
    code_verifier = generate_code_verifier()
    code_challenge = generate_code_challenge(code_verifier)
    
    session['code_verifier'] = code_verifier
    
    params = {
        'response_type': 'code',
        'client_id': config['client_id'],
        'redirect_uri': config['redirect_uri'],
        'scope': config['scope'],
        'state': secrets.token_urlsafe(32),
        'code_challenge': code_challenge,
        'code_challenge_method': 'S256'
    }
    
    auth_url = f"{provider_config['authorization_endpoint']}?{urllib.parse.urlencode(params)}"
    return redirect(auth_url)

@app.route('/callback')
def callback():
    config = get_oidc_config()
    provider_config = get_provider_config()
    
    error = request.args.get('error')
    if error:
        return f"Error: {error}"
    
    code = request.args.get('code')
    state = request.args.get('state')
    
    if not code:
        return "No authorization code received"
    
    # Exchange code for tokens
    token_data = {
        'grant_type': 'authorization_code',
        'client_id': config['client_id'],
        'client_secret': config['client_secret'],
        'code': code,
        'redirect_uri': config['redirect_uri'],
        'code_verifier': session.get('code_verifier')
    }
    
    token_response = requests.post(
        provider_config['token_endpoint'],
        data=token_data
    )
    
    if token_response.status_code != 200:
        return "Failed to exchange code for tokens"
    
    token_info = token_response.json()
    
    # Decode ID token
    id_token = token_info.get('id_token')
    if not id_token:
        return "No ID token received"
    
    # Split the JWT token
    token_parts = id_token.split('.')
    if len(token_parts) != 3:
        return "Invalid ID token format"
    
    # Decode payload (second part)
    payload = token_parts[1]
    # Add padding if needed
    payload += '=' * (4 - len(payload) % 4)
    decoded_payload = base64.urlsafe_b64decode(payload)
    user_claims = json.loads(decoded_payload)
    
    # Store user info in session
    session['user'] = {
        'sub': user_claims.get('sub'),
        'name': user_claims.get('name'),
        'email': user_claims.get('email'),
        'preferred_username': user_claims.get('preferred_username')
    }
    
    return redirect(url_for('index'))

@app.route('/logout')
def logout():
    session.clear()
    return redirect(url_for('index'))

if __name__ == '__main__':
    app.run(debug=True)